// monster-swarm — the distributed-inference guardrails of the monster family.
//
// UCAN-gated, cost-admitted CRUD over a leased swarm of distributed-inference
// subagents. Every mutation is verified (capability rooted at the shared
// resident root, granting agent/<verb> on agent:fleet) AND admitted by the
// AntColony FRF budget (population ceiling + two-queen reap floor), then
// enforced at runtime by monster-guard (sandbox + lease + revoke).
//
// Usage:
//   monster-swarm whoami
//   monster-swarm spawn  --ucan <t> --node <bin> [--id <id>] [--caste scout|breeder]
//                        [--caps net,fs] [--lease <secs>] [--max <secs>]
//                        [--grant-ttl <secs>] [--qspec <file>] [--oath <file>] [-- <node args...>]
//   monster-swarm list   [--json]
//   monster-swarm update --ucan <t> --id <id> [--caps net,fs] [--lease <secs>] [--grant-ttl <secs>]
//   monster-swarm reap   --ucan <t> --id <id> [--cascade] [--json]
//   monster-swarm audit  [--json] [--verify]   tamper-evident lifecycle chain
//   monster-swarm vibe   [--dwell-ms <ms>] [--json]
//   monster-swarm broadcast --consciousness <0-5> [--energy <n>] [--pitch <n>]
//                        [--phase <n>] [--recalibration] [--id <source_id>]
//                        [--hz <rate>] [--secs <duration>] [--count <n>] [--json]
//   monster-swarm sign        --id <id> --msg <msg>
//   monster-swarm verify-sig  --id <id> --msg <msg> --sig <hex>
//
// The CRUD core lives in `monster_swarm::ops` (shared with the monster-resident
// MCP tools); this binary is a thin CLI front-end over it.

use std::time::Duration;

use monster_swarm::audit;
use monster_swarm::auto::{self, AutoPolicy};
use monster_swarm::budget::{Caste, FleetBudget};
use monster_swarm::oath;
use monster_swarm::ops::{
    self, DelegateSpawnRequest, SpawnRequest, UpdateRequest, DEFAULT_GRANT_TTL_SECS,
    DEFAULT_LEASE_SECS,
};
use monster_swarm::sign;
use monster_swarm::store;
use monster_swarm::swarm::{self, SwarmSignal};

use a0n_auth::Keypair;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    match args.get(1).map(String::as_str) {
        Some("whoami") => cmd_whoami(),
        Some("spawn") | Some("create") => cmd_spawn(&args[2..]),
        Some("delegate-spawn") => cmd_delegate_spawn(&args[2..]),
        Some("list") | Some("read") => cmd_list(&args[2..]),
        Some("update") => cmd_update(&args[2..]),
        Some("reap") | Some("delete") | Some("revoke") => cmd_reap(&args[2..]),
        Some("oath-breach") => cmd_oath_breach(&args[2..]),
        Some("breaches") => cmd_breaches(&args[2..]),
        Some("audit") => cmd_audit(&args[2..]),
        Some("trust") => cmd_trust(&args[2..]),
        Some("vibe") => cmd_vibe(&args[2..]),
        Some("broadcast") => cmd_broadcast(&args[2..]),
        Some("sign") => cmd_sign(&args[2..]),
        Some("verify-sig") => cmd_verify_sig(&args[2..]),
        Some("oath") => cmd_oath(&args[2..]),
        Some("auto") => cmd_auto(&args[2..]),
        Some("reconcile") => cmd_reconcile(),
        Some("-h") | Some("--help") | None => usage(),
        Some(other) => {
            eprintln!("monster-swarm: unknown subcommand '{other}'");
            usage();
            std::process::exit(2);
        }
    }
}

