    println!("monster-swarm — UCAN-gated, cost-admitted CRUD over a leased subagent swarm");
    println!();
    println!("  monster-swarm whoami");
    println!("  monster-swarm spawn  --ucan <t> --node <bin> [--id <id>] [--caste scout|breeder]");
