    println!("  monster-swarm delegate-spawn --ucan <parent-token> --issuer-secret <hex> --to <child-did>");
    println!("                       --caps <subset csv> [--ttl <secs>]   attenuated delegation of spawn authority");
    println!("  monster-swarm list   [--json]");
    println!("  monster-swarm update --ucan <t> --id <id> [--caps net,fs] [--lease <secs>] [--grant-ttl <secs>]");
    println!("  monster-swarm reap   --ucan <t> --id <id> [--cascade] [--json]   --cascade reaps the spawned subtree");
    println!("  monster-swarm oath-breach --ucan <t> --id <id> --reason <r> [--sig <hex>]");
    println!("  monster-swarm breaches    [--json]");
    println!("  monster-swarm audit       [--json] [--verify]   tamper-evident lifecycle chain");
    println!("  monster-swarm trust       [--json]   spawner reputation (trust + breach count)");
    println!("  monster-swarm vibe   [--dwell-ms <ms>] [--json]");
    println!("  monster-swarm broadcast --consciousness <0-5> [--energy <n>] [--pitch <n>] [--phase <n>]");
    println!("                       [--recalibration] [--id <source_id>] [--hz <rate>] [--secs <duration>] [--count <n>] [--json]");
