fn cmd_breaches(args: &[String]) {
    let json = args.iter().any(|a| a == "--json");
    let log = ops::breaches();
    if json {
        println!("{}", serde_json::to_string_pretty(&log).unwrap_or_default());
        return;
    }
    if log.is_empty() {
        println!("monster-swarm: no oath breaches recorded");
        return;
    }
    println!("monster-swarm: {} oath breach(es) on record", log.len());
    for b in &log {
        let sworn = b.oath_sworn_by.as_deref().unwrap_or("-");
        let verified = if b.verified { " [verified]" } else { "" };
        println!(
            "  {:<14} {:<8} ts {:>10}  sworn-by {}  by {}{}\n      reason: {}",
            b.id, b.caste, b.ts, sworn, b.reported_by, verified, b.reason
        );
    }
}

fn cmd_audit(args: &[String]) {
    let json = args.iter().any(|a| a == "--json");
    let do_verify = args.iter().any(|a| a == "--verify");
    for a in args {
        if a != "--json" && a != "--verify" {
            die(format!("audit: unexpected argument '{a}'"));
        }
    }

    // --verify: walk the chain and report the verdict. The JSON shape and exit
    // codes are a hard interface other tools code against: exactly
    // {"ok":bool,"entries":N,"first_bad":null|seq,"reason":"...","head":"<hash>"}
    // on stdout, exit 0 if ok else exit 3.
    if do_verify {
        let report = audit::verify();
        if json {
            println!(
                "{}",
                serde_json::json!({
                    "ok": report.ok,
                    "entries": report.entries,
                    "first_bad": report.first_bad,
                    "reason": report.reason,
                    "head": report.head,
                })
            );
        } else if report.ok {
            println!(
                "monster-swarm: audit chain OK — {} entr{} verified, head {}",
                report.entries,
                if report.entries == 1 { "y" } else { "ies" },
                short_hash(&report.head),
            );
        } else {
            let at = report
                .first_bad
                .map(|s| format!("seq {s}"))
                .unwrap_or_else(|| "?".to_string());
            println!(
                "monster-swarm: audit chain TAMPERED — {} at {at}: {}",
                report.entries, report.reason,
            );
        }
        std::process::exit(if report.ok { 0 } else { 3 });
    }

    // No --verify: tail (or dump) the chain.
    let chain = audit::load();
    if json {
        println!(
            "{}",
            serde_json::json!({ "entries": chain }),
        );
        return;
    }
    if chain.is_empty() {
        println!("monster-swarm: no audit events recorded");
        return;
    }
    // Human tail: the last ~20 events (seq, kind, subject, short hash).
    let tail = if chain.len() > 20 { &chain[chain.len() - 20..] } else { &chain[..] };
    println!(
        "monster-swarm: {} audit event(s) — showing last {}",
        chain.len(),
        tail.len(),
    );
    for e in tail {
        println!(
            "  #{:<5} {:<9} {:<20} {}",
            e.seq,
            audit_kind_str(e.kind),
            truncate(&e.subject, 20),
            short_hash(&e.hash),
        );
    }
}

/// The first 12 hex chars of a chain hash — enough to eyeball, short enough to
/// fit a tail row. The genesis sentinel prints as `genesis`.
fn short_hash(h: &str) -> String {
    if h == audit::GENESIS_PREV_HASH {
        return "genesis".to_string();
    }
    h.chars().take(12).collect()
}

/// The lowercase snake string for an event kind (the serde wire form), for the
/// human tail. Falls back to "?" if the kind ever fails to serialize.
fn audit_kind_str(kind: audit::EventKind) -> String {
    serde_json::to_value(kind)
        .ok()
        .and_then(|v| v.as_str().map(String::from))
        .unwrap_or_else(|| "?".to_string())
}

fn truncate(s: &str, n: usize) -> String {
    if s.chars().count() <= n {
        s.to_string()
    } else {
        let kept: String = s.chars().take(n.saturating_sub(2)).collect();
        format!("{kept}..")
    }
}

fn cmd_trust(args: &[String]) {
    let json = args.iter().any(|a| a == "--json");
    let rows = ops::trusts();
    if json {
        println!("{}", serde_json::to_string_pretty(&rows).unwrap_or_default());
        return;
    }
    if rows.is_empty() {
        println!("monster-swarm: all spawners fully trusted (no oath breaches on record)");
        return;
    }
    println!(
        "monster-swarm: {} spawner(s) with a reputation cost (trust floor {:.2})",
        rows.len(),
        ops::min_trust(),
    );
    for r in &rows {
        let gated = if r.trust < ops::min_trust() { " [BELOW FLOOR — spawns denied]" } else { "" };
        println!("  trust {:.2}  breaches {:<3}  {}{}", r.trust, r.breaches, r.did, gated);
    }
}

fn cmd_vibe(args: &[String]) {
    let mut dwell_ms = 800u64;
    let mut json = false;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--dwell-ms" => { i += 1; dwell_ms = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(800); }
            "--json" => json = true,
            other => die(format!("vibe: unexpected argument '{other}'")),
        }
        i += 1;
    }
    match ops::vibe(Duration::from_millis(dwell_ms)) {
        Ok(o) => {
            if json {
                println!("{}", serde_json::to_string_pretty(&o.frame).unwrap_or_default());
                return;
            }
            let c = &o.frame["consciousness"];
            let f = &o.frame["fleet"];
            println!("monster-swarm: swarm vibe over {dwell_ms}ms — {} node(s) talking", o.nodes_talking);
            println!(
                "  collective: energy {}, consciousness {}, phase {}",
                c["energy"], c["consciousness"], c["phase"]
            );
            println!(
                "  fleet: {} live ({} breeders, {} scouts), stability weight {}",
                f["live"], f["breeders"], f["scouts"], f["stabilityWeight"]
            );
        }
        Err(e) => die(e),
    }
}

// broadcast — emit SwarmSignal(s) onto the UDP partyline (255.255.255.255:4242),
// exactly what a live distributed-inference node emits, made scriptable. One-shot
// by default; with --secs (and --hz, default 5) or --count it repeats the emission
// so a background process can hold the collective vibe hot (or calm) while a
// controller ticks. A concise line per emission goes to STDERR so captures stay
// clean; with --json the summary {"emitted":N,"consciousness":C,"source_id":"..."}
// goes to stdout. This replaces the need for a live aeon-monitor in tests/demos.
fn cmd_broadcast(args: &[String]) {
    let mut consciousness: Option<u32> = None;
    let mut energy: u32 = 50;
    let mut pitch_class: u32 = 0;
    let mut phase: u8 = 0;
    let mut recalibration = false;
    let mut source_id: Option<String> = None;
    let mut hz: f64 = 5.0;
    let mut secs: Option<f64> = None;
    let mut count: Option<u64> = None;
    let mut json = false;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--consciousness" => { i += 1; consciousness = args.get(i).and_then(|s| s.parse().ok()); }
            "--energy" => { i += 1; energy = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(energy); }
            "--pitch" => { i += 1; pitch_class = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(pitch_class); }
            "--phase" => { i += 1; phase = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(phase); }
            "--recalibration" => recalibration = true,
            "--id" => { i += 1; source_id = args.get(i).cloned(); }
            "--hz" => { i += 1; hz = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(hz); }
            "--secs" => { i += 1; secs = args.get(i).and_then(|s| s.parse().ok()); }
            "--count" => { i += 1; count = args.get(i).and_then(|s| s.parse().ok()); }
            "--json" => json = true,
            other => die(format!("broadcast: unexpected argument '{other}'")),
        }
        i += 1;
    }

    let consciousness = consciousness.unwrap_or_else(|| die("broadcast: --consciousness <0-5> required"));
    if consciousness > 5 {
        die(format!("broadcast: --consciousness must be 0..=5, got {consciousness}"));
    }
    if hz <= 0.0 {
        die("broadcast: --hz must be > 0");
    }
    let source_id = source_id.unwrap_or_else(|| format!("cli-{}", std::process::id()));

    let signal = SwarmSignal {
        source_id: source_id.clone(),
        energy,
        consciousness,
        pitch_class,
        phase,
        recalibration_event: recalibration,
    };

    // How many emissions: --count wins; else --secs * hz (at least 1); else one-shot.
    let total: u64 = match (count, secs) {
        (Some(n), _) => n,
        (None, Some(s)) => ((s * hz).round() as u64).max(1),
        (None, None) => 1,
    };
    let period = Duration::from_secs_f64(1.0 / hz);

    let mut emitted: u64 = 0;
    for n in 0..total {
        match swarm::broadcast(&signal) {
            Ok(()) => {
                emitted += 1;
                eprintln!(
                    "monster-swarm: broadcast [{}/{}] source_id={} consciousness={} energy={}{}",
                    emitted,
                    total,
                    source_id,
                    consciousness,
                    energy,
                    if recalibration { " recalibration" } else { "" },
                );
            }
            Err(e) => {
                // A failed emit (e.g. no UDP broadcast in a sandbox) is reported to
                // stderr; if NOTHING got out, exit non-zero so a driver can detect it.
                eprintln!("monster-swarm: broadcast error — {e}");
                if emitted == 0 {
                    die(format!("broadcast: could not emit on the partyline: {e}"));
                }
                break;
            }
        }
        // Sleep between emissions (not after the last one).
        if n + 1 < total {
            std::thread::sleep(period);
        }
    }

    if json {
        println!(
            "{}",
            serde_json::json!({
                "emitted": emitted,
                "consciousness": consciousness,
                "source_id": source_id,
            })
        );
    }
}

fn cmd_sign(args: &[String]) {
    let mut id: Option<String> = None;
    let mut msg: Option<String> = None;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--id" => { i += 1; id = args.get(i).cloned(); }
            "--msg" => { i += 1; msg = args.get(i).cloned(); }
            other => die(format!("sign: unexpected argument '{other}'")),
        }
        i += 1;
    }
    let id = id.unwrap_or_else(|| die("sign: --id <id> required"));
    let msg = msg.unwrap_or_else(|| die("sign: --msg <msg> required"));
    match sign::sign_with_keyfile(&id, msg.as_bytes()) {
        Ok(sig) => println!("{}", hex::encode(sig)),
        Err(e) => die(e),
    }
}

fn cmd_verify_sig(args: &[String]) {
    let mut id: Option<String> = None;
    let mut msg: Option<String> = None;
    let mut sig: Option<String> = None;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--id" => { i += 1; id = args.get(i).cloned(); }
            "--msg" => { i += 1; msg = args.get(i).cloned(); }
            "--sig" => { i += 1; sig = args.get(i).cloned(); }
            other => die(format!("verify-sig: unexpected argument '{other}'")),
        }
        i += 1;
    }
    let id = id.unwrap_or_else(|| die("verify-sig: --id <id> required"));
    let msg = msg.unwrap_or_else(|| die("verify-sig: --msg <msg> required"));
    let sig = sig.unwrap_or_else(|| die("verify-sig: --sig <hex> required"));
    let sig_bytes = hex::decode(sig.trim()).unwrap_or_else(|e| die(format!("verify-sig: bad --sig hex: {e}")));
    if sign::verify_subagent_signature(&id, msg.as_bytes(), &sig_bytes) {
        println!("OK");
    } else {
        println!("FAIL");
        std::process::exit(2);
    }
}

// oath mint — mint an agent's self-signed Ulysses oath-token from a terms file,
// using that agent's EXISTING keyfile (store::agent_key_path). The agent ties
// itself to the mast: iss = aud = the agent DID, the oath terms bound as fct,
// granting oath/uphold over agent:self:<id>. Useful standalone (the spawn path
// mints automatically). Writes to --out, or prints the token to stdout.
fn cmd_oath(args: &[String]) {
    match args.first().map(String::as_str) {
        Some("mint") => cmd_oath_mint(&args[1..]),
        Some(other) => die(format!("oath: unknown subcommand '{other}' (expected 'mint')")),
        None => die("oath: usage: monster-swarm oath mint --id <id> --terms <file> [--ttl <secs>] [--out <file>]"),
    }
}

fn cmd_oath_mint(args: &[String]) {
    let mut id: Option<String> = None;
    let mut terms: Option<String> = None;
    let mut ttl = DEFAULT_GRANT_TTL_SECS;
    let mut out: Option<String> = None;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--id" => { i += 1; id = args.get(i).cloned(); }
            "--terms" => { i += 1; terms = args.get(i).cloned(); }
            "--ttl" => { i += 1; ttl = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(DEFAULT_GRANT_TTL_SECS); }
            "--out" => { i += 1; out = args.get(i).cloned(); }
            other => die(format!("oath mint: unexpected argument '{other}'")),
        }
        i += 1;
    }
    let id = id.unwrap_or_else(|| die("oath mint: --id <id> required"));
    let terms_file = terms.unwrap_or_else(|| die("oath mint: --terms <file> required"));

    // Load the agent's EXISTING secret from its 0600 keyfile and reconstruct its
    // keypair — the same key it signs invocations with. The agent must already
    // have been spawned (its keyfile minted at spawn).
    let key_path = store::agent_key_path(&id);
    let secret_hex = std::fs::read_to_string(&key_path)
        .unwrap_or_else(|e| die(format!("oath mint: read agent keyfile {}: {e}", key_path.display())));
    let kp = Keypair::from_secret_hex(secret_hex.trim())
        .unwrap_or_else(|e| die(format!("oath mint: bad agent key: {e}")));

    // Read + validate the raw oath terms and have the agent SWEAR them: a Ulysses
    // self-signed oath-token (iss = aud = agent DID).
    let text = std::fs::read_to_string(&terms_file)
        .unwrap_or_else(|e| die(format!("oath mint: read terms '{terms_file}': {e}")));
    let parsed = oath::parse_terms(&text).unwrap_or_else(|e| die(format!("oath mint: {e}")));
    let token = oath::mint_self_oath_token(&kp, &id, parsed, ttl, None)
        .unwrap_or_else(|e| die(format!("oath mint: {e}")));

    match out {
        Some(path) => {
            std::fs::write(&path, &token)
                .unwrap_or_else(|e| die(format!("oath mint: write '{path}': {e}")));
            eprintln!("monster-swarm: minted Ulysses oath-token for '{id}' (sworn by {}) -> {path}", kp.did());
        }
        None => println!("{token}"),
    }
}

fn cmd_reconcile() {
    let o = ops::reconcile();
    if o.pruned.is_empty() {
        println!("monster-swarm: fleet reconciled — {} live, nothing pruned", o.live);
    } else {
        println!(
            "monster-swarm: reconciled — pruned {} dead ({}), {} live",
            o.pruned.len(),
            o.pruned.join(", "),
            o.live
        );
    }
}

fn cmd_auto(args: &[String]) {
    let mut ucan: Option<String> = None;
    let mut policy = AutoPolicy::default();
    let mut dwell_ms = 800u64;
    let mut interval: Option<u64> = None;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--ucan" => { i += 1; ucan = args.get(i).cloned(); }
            "--node" => { i += 1; if let Some(v) = args.get(i) { policy.node_bin = v.clone(); } }
            "--bud-at" => { i += 1; if let Some(v) = args.get(i).and_then(|s| s.parse().ok()) { policy.bud_at_consciousness = v; } }
            "--reap-below" => { i += 1; if let Some(v) = args.get(i).and_then(|s| s.parse().ok()) { policy.reap_below_consciousness = v; } }
            "--min-live" => { i += 1; if let Some(v) = args.get(i).and_then(|s| s.parse().ok()) { policy.min_live = v; } }
            "--caps" => { i += 1; policy.caps = parse_caps(args.get(i).map(String::as_str).unwrap_or("")); }
            "--lease" => { i += 1; if let Some(v) = args.get(i).and_then(|s| s.parse().ok()) { policy.lease_secs = v; } }
            "--enforce-oaths" => { policy.enforce_oaths = true; }
            "--breach-at" => { i += 1; if let Some(v) = args.get(i).and_then(|s| s.parse().ok()) { policy.breach_at = v; } }
            "--dwell-ms" => { i += 1; dwell_ms = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(800); }
            "--interval" => { i += 1; interval = args.get(i).and_then(|s| s.parse().ok()); }
            other => die(format!("auto: unexpected argument '{other}'")),
        }
        i += 1;
    }
    let ucan = ucan.unwrap_or_else(|| die("auto: --ucan <token> required"));
    let tick = || match auto::autotick(&ucan, &policy, Duration::from_millis(dwell_ms)) {
        Ok(o) => println!(
            "monster-swarm: auto [{}] {} ({} node(s) talking)",
            o.action, o.reason, o.nodes_talking
        ),
        Err(e) => eprintln!("monster-swarm: auto tick error — {e}"),
    };
    match interval {
        None => tick(),
        Some(secs) => {
            println!("monster-swarm: autonomic loop every {secs}s (Ctrl-C to stop)");
            loop {
                tick();
                std::thread::sleep(Duration::from_secs(secs.max(1)));
            }
        }
    }
}
